import React, { useState, useEffect } from 'react';
import './ArticleForm.css';

const ArticleForm = ({ selectedArticle, onSuccess }) => {
  const [formData, setFormData] = useState({
    codeArt: '',
    nomArt: '',
    prix: '',
    Stock_disponible: ''
  });

  useEffect(() => {
    if (selectedArticle) setFormData(selectedArticle);
    else resetForm();
  }, [selectedArticle]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      codeArt: '',
      nomArt: '',
      prix: '',
      Stock_disponible: ''
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const method = selectedArticle ? 'PUT' : 'POST';
    const url = selectedArticle
      ? `http://localhost:3001/articles/${formData.codeArt}`
      : 'http://localhost:3001/articles';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });
      if (!res.ok) throw new Error(`Erreur ${res.status}`);
      if (!selectedArticle) resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  const handleDelete = async () => {
    if (!selectedArticle) return;
    if (!window.confirm('Supprimer cet article ?')) return;

    try {
      const res = await fetch(`http://localhost:3001/articles/${selectedArticle.codeArt}`, {
        method: 'DELETE'
      });
      if (!res.ok) throw new Error(`Erreur ${res.status}`);
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input name="codeArt" placeholder="Code Article" value={formData.codeArt} onChange={handleChange} required={!selectedArticle} disabled={!!selectedArticle} />
      <input name="nomArt" placeholder="Nom Article" value={formData.nomArt} onChange={handleChange} required />
      <input name="prix" placeholder="Prix" value={formData.prix} onChange={handleChange} required />
      <input name="Stock_disponible" placeholder="Stock Disponible" value={formData.Stock_disponible} onChange={handleChange} required />
      <button type="submit">{selectedArticle ? 'Modifier' : 'Ajouter'}</button>
      {selectedArticle && <button type="button" onClick={handleDelete}>Supprimer</button>}
    </form>
  );
};

export default ArticleForm;
